/* ---------------- loader: serif counter with slide-up exit ---------------- */
function Loader({ done }) {
  const [n, setN] = useState(0);
  const [exit, setExit] = useState(false);
  useEffect(() => {
    const start = performance.now();
    let raf;
    const tick = (t) => {
      const p = Math.min(100, Math.round(((t - start) / 1600) * 100));
      setN(p);
      if (p < 100) raf = requestAnimationFrame(tick);
      else { setExit(true); setTimeout(done, 700); }
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [done]);
  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 100, background: C.bg,
      display: "flex", alignItems: "flex-end", justifyContent: "space-between",
      padding: "clamp(24px,5vw,60px)",
      transform: exit ? "translateY(-100%)" : "none",
      transition: `transform .7s ${EASE}`,
    }}>
      <div>
        <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 12, color: C.dim, letterSpacing: ".15em", display: "block" }}>
          MADALITSO DAKA — PORTFOLIO
        </span>
        <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 11, color: C.faint, letterSpacing: ".15em", display: "block", marginTop: 8 }}>
          VERIFYING CLAIMS<span style={{ color: C.accent }}>…</span>
        </span>
      </div>
      <span style={{
        fontFamily: "'Instrument Serif',serif", fontStyle: "italic",
        fontSize: "clamp(80px,16vw,200px)", lineHeight: 0.8, color: C.text,
      }}>{n}</span>
    </div>
  );
}

/* ---------------- FEATURE: scroll-scrubbed typing ----------------
   Characters reveal as you scroll down and un-reveal as you scroll
   back up — progress is bound to scroll position, so it's fully
   reversible, with a live caret at the write-head. */
function ScrollType({ text, size = "clamp(28px,4.6vw,58px)" }) {
  const ref = useRef(null);
  const [prog, setProg] = useState(0);
  useEffect(() => {
    const on = () => {
      if (!ref.current) return;
      const r = ref.current.getBoundingClientRect();
      const vh = window.innerHeight;
      // starts when block enters lower third, completes near upper third
      const p = (vh * 0.8 - r.top) / (vh * 0.6);
      setProg(Math.max(0, Math.min(1, p)));
    };
    window.addEventListener("scroll", on, { passive: true }); on();
    return () => window.removeEventListener("scroll", on);
  }, []);
  const chars = text.split("");
  const head = Math.floor(prog * chars.length);
  return (
    <p ref={ref} aria-label={text} style={{
      fontFamily: "'Inter Tight',sans-serif", fontWeight: 600,
      fontSize: size, letterSpacing: "-0.03em", lineHeight: 1.25,
      margin: 0, maxWidth: "22em",
    }}>
      {chars.map((ch, i) => (
        <span key={i} aria-hidden style={{
          color: i < head ? C.text : "rgba(237,240,228,0.14)",
          transition: "color .18s linear",
        }}>{ch}</span>
      ))}
      <span aria-hidden style={{
        display: "inline-block", width: "0.08em", height: "0.95em",
        background: C.accent, marginLeft: 2, verticalAlign: "-0.12em",
        opacity: prog > 0.02 && prog < 0.99 ? 1 : 0, transition: "opacity .2s",
      }} />
    </p>
  );
}

