/* ---------------- FEATURE: contextual cursor ----------------
   A small dot that follows the mouse; near interactive zones it
   expands into a labelled chip ("VIEW", "FLIP", "OPEN") — the
   pattern on most current Awwwards portfolio honors. */
function ContextCursor() {
  const dotRef = useRef(null);
  const [label, setLabel] = useState("");
  useEffect(() => {
    if (window.matchMedia("(pointer: coarse)").matches) return; // skip on touch
    let x = -100, y = -100, cx = -100, cy = -100, raf;
    const move = (e) => {
      x = e.clientX; y = e.clientY;
      const t = e.target.closest("[data-cursor]");
      setLabel(t ? t.getAttribute("data-cursor") : "");
    };
    const loop = () => {
      cx += (x - cx) * 0.18; cy += (y - cy) * 0.18;
      if (dotRef.current) dotRef.current.style.transform = `translate(${cx}px,${cy}px) translate(-50%,-50%)`;
      raf = requestAnimationFrame(loop);
    };
    window.addEventListener("mousemove", move); loop();
    return () => { window.removeEventListener("mousemove", move); cancelAnimationFrame(raf); };
  }, []);
  return (
    <div ref={dotRef} style={{
      position: "fixed", left: 0, top: 0, zIndex: 80, pointerEvents: "none",
      display: "flex", alignItems: "center", justifyContent: "center",
      width: label ? 64 : 10, height: label ? 64 : 10, borderRadius: 99,
      background: label ? "rgba(155,201,126,.95)" : C.accent,
      transition: "width .35s cubic-bezier(.2,.9,.2,1), height .35s cubic-bezier(.2,.9,.2,1), background .35s",
      mixBlendMode: label ? "normal" : "difference",
    }}>
      {label && <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 10, fontWeight: 700, color: C.bg, letterSpacing: ".1em" }}>{label}</span>}
    </div>
  );
}

