/* ---------------- hooks ---------------- */
const useFonts = () => {
  useEffect(() => {
    const l = document.createElement("link");
    l.rel = "stylesheet"; l.href = FONTS; document.head.appendChild(l);
  }, []);
};
const useInView = (t = 0.15) => {
  const ref = useRef(null); const [v, setV] = useState(false);
  useEffect(() => {
    const o = new IntersectionObserver(([e]) => e.isIntersecting && setV(true), { threshold: t });
    if (ref.current) o.observe(ref.current); return () => o.disconnect();
  }, [t]);
  return [ref, v];
};
const Reveal = ({ children, delay = 0, style }) => {
  const [ref, v] = useInView();
  return <div ref={ref} style={{ opacity: v ? 1 : 0, transform: v ? "none" : "translateY(30px)", transition: `opacity 1s ${EASE} ${delay}ms, transform 1s ${EASE} ${delay}ms`, ...style }}>{children}</div>;
};

/* ---------------- FEATURE: magnetic button ---------------- */
function Magnetic({ children, strength = 0.35, style, ...rest }) {
  const ref = useRef(null);
  const onMove = (e) => {
    const r = ref.current.getBoundingClientRect();
    const x = (e.clientX - r.left - r.width / 2) * strength;
    const y = (e.clientY - r.top - r.height / 2) * strength;
    ref.current.style.transform = `translate(${x}px,${y}px)`;
  };
  const onLeave = () => (ref.current.style.transform = "translate(0,0)");
  return (
    <a ref={ref} onMouseMove={onMove} onMouseLeave={onLeave} className="btn" style={style} {...rest}>
      {children}
    </a>
  );
}

/* ---------------- FEATURE: spotlight blueprint cursor ---------------- */
function Spotlight() {
  const [p, setP] = useState({ x: -500, y: -500 });
  const [enabled, setEnabled] = useState(true);
  useEffect(() => {
    if (window.matchMedia("(pointer: coarse)").matches) { setEnabled(false); return; }
    const on = (e) => setP({ x: e.clientX, y: e.clientY });
    window.addEventListener("mousemove", on);
    return () => window.removeEventListener("mousemove", on);
  }, []);
  if (!enabled) return null;
  return (
    <div aria-hidden style={{
      position: "fixed", inset: 0, pointerEvents: "none", zIndex: 1,
      backgroundImage: `linear-gradient(rgba(155,201,126,.14) 1px, transparent 1px), linear-gradient(90deg, rgba(155,201,126,.14) 1px, transparent 1px)`,
      backgroundSize: "48px 48px",
      WebkitMaskImage: `radial-gradient(240px at ${p.x}px ${p.y}px, black, transparent 70%)`,
      maskImage: `radial-gradient(240px at ${p.x}px ${p.y}px, black, transparent 70%)`,
    }} />
  );
}

/* ---------------- FEATURE: command palette (⌘K) ---------------- */
const COMMANDS = [
  { k: "Go to Work", hint: "flagship + case outlines", href: "#work" },
  { k: "Go to Skills", hint: "capability grid", href: "#skills" },
  { k: "Go to Method", hint: "operating principles", href: "#method" },
  { k: "Contact", hint: "open channel", href: "#contact" },
  { k: "Download CV", hint: "pdf — placeholder", href: "#" },
  { k: "Copy email", hint: CONFIG.email, action: "email" },
];
function CommandPalette({ open, setOpen }) {
  const [q, setQ] = useState("");
  const inputRef = useRef(null);
  useEffect(() => {
    const onKey = (e) => {
      if ((e.metaKey || e.ctrlKey) && e.key.toLowerCase() === "k") { e.preventDefault(); setOpen((o) => !o); }
      if (e.key === "Escape") setOpen(false);
    };
    window.addEventListener("keydown", onKey);
    return () => window.removeEventListener("keydown", onKey);
  }, [setOpen]);
  useEffect(() => { if (open) setTimeout(() => inputRef.current?.focus(), 50); else setQ(""); }, [open]);
  if (!open) return null;
  const list = COMMANDS.filter((c) => c.k.toLowerCase().includes(q.toLowerCase()));
  const run = (c) => {
    if (c.action === "email") navigator.clipboard?.writeText(CONFIG.email);
    else if (c.href) document.querySelector(c.href)?.scrollIntoView({ behavior: "smooth" });
    setOpen(false);
  };
  return (
    <div onClick={() => setOpen(false)} style={{ position: "fixed", inset: 0, zIndex: 60, background: "rgba(5,6,5,.7)", backdropFilter: "blur(8px)", display: "flex", justifyContent: "center", paddingTop: "18vh" }}>
      <div onClick={(e) => e.stopPropagation()} style={{
        width: "min(560px, 92vw)", height: "fit-content", borderRadius: 20,
        background: C.surface, border: `1px solid ${C.borderHover}`,
        boxShadow: `0 40px 120px -20px rgba(0,0,0,.9), 0 0 80px -30px rgba(155,201,126,.3)`,
        overflow: "hidden", animation: `fadeUp .35s ${EASE} both`,
      }}>
        <input ref={inputRef} value={q} onChange={(e) => setQ(e.target.value)}
          placeholder="Where to? Try 'work'…"
          style={{ width: "100%", background: "transparent", border: "none", outline: "none", color: C.text, fontSize: 17, fontFamily: "'Inter Tight',sans-serif", padding: "20px 24px", borderBottom: `1px solid ${C.border}` }} />
        {list.map((c) => (
          <button key={c.k} onClick={() => run(c)} style={{
            display: "flex", width: "100%", justifyContent: "space-between", alignItems: "center",
            background: "transparent", border: "none", cursor: "pointer",
            padding: "15px 24px", color: C.text, fontSize: 15, fontFamily: "'Inter Tight',sans-serif",
          }}
            onMouseEnter={(e) => (e.currentTarget.style.background = "rgba(155,201,126,.06)")}
            onMouseLeave={(e) => (e.currentTarget.style.background = "transparent")}>
            <span>{c.k}</span>
            <span style={{ fontSize: 12, color: C.faint, fontFamily: "'JetBrains Mono',monospace" }}>{c.hint}</span>
          </button>
        ))}
        <div style={{ padding: "12px 24px", borderTop: `1px solid ${C.border}`, fontSize: 11, color: C.faint, fontFamily: "'JetBrains Mono',monospace" }}>
          ↵ select · esc close — this site works like my software: navigable, instrumented, fast
        </div>
      </div>
    </div>
  );
}

/* ---------------- FEATURE: live Lusaka clock ---------------- */
function LusakaClock() {
  const [t, setT] = useState("");
  useEffect(() => {
    const tick = () => setT(new Intl.DateTimeFormat("en-GB", { hour: "2-digit", minute: "2-digit", second: "2-digit", timeZone: "Africa/Lusaka" }).format(new Date()));
    tick(); const i = setInterval(tick, 1000); return () => clearInterval(i);
  }, []);
  return (
    <span style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 11, color: C.dim, letterSpacing: ".1em" }}>
      LUSAKA <span style={{ color: C.accent }}>{t}</span> CAT
    </span>
  );
}

